# Script de Teste de Todos os Serviços
# Uso: .\test-services.ps1

Write-Host "`n====================================" -ForegroundColor Cyan
Write-Host "   TESTANDO TODOS OS SERVIÇOS" -ForegroundColor Cyan
Write-Host "====================================`n" -ForegroundColor Cyan

$allPassed = $true

# Test 1: PostgreSQL
Write-Host "🔍 Testando PostgreSQL..." -ForegroundColor Yellow
try {
    $result = docker exec postgres pg_isready -U postgres 2>&1
    if ($result -match "accepting connections") {
        Write-Host "   ✅ PostgreSQL: OK" -ForegroundColor Green
    } else {
        Write-Host "   ❌ PostgreSQL: FALHOU" -ForegroundColor Red
        $allPassed = $false
    }
} catch {
    Write-Host "   ❌ PostgreSQL: ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 2: Redis
Write-Host "`n🔍 Testando Redis..." -ForegroundColor Yellow
try {
    $result = docker exec docker-n8n-evo-redis-1 redis-cli -a oPvT2rgzcoVtwqDCAYhMz76I ping 2>&1
    if ($result -match "PONG") {
        Write-Host "   ✅ Redis: OK" -ForegroundColor Green
    } else {
        Write-Host "   ❌ Redis: FALHOU" -ForegroundColor Red
        $allPassed = $false
    }
} catch {
    Write-Host "   ❌ Redis: ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 3: Evolution API
Write-Host "`n🔍 Testando Evolution API..." -ForegroundColor Yellow
try {
    $response = Invoke-WebRequest -Uri "http://localhost:8080" -UseBasicParsing -TimeoutSec 5
    $content = $response.Content | ConvertFrom-Json
    if ($content.status -eq 200) {
        Write-Host "   ✅ Evolution API: OK (v$($content.version))" -ForegroundColor Green
    } else {
        Write-Host "   ❌ Evolution API: FALHOU" -ForegroundColor Red
        $allPassed = $false
    }
} catch {
    Write-Host "   ❌ Evolution API: ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 4: Chatwoot
Write-Host "`n🔍 Testando Chatwoot..." -ForegroundColor Yellow
try {
    $response = Invoke-WebRequest -Uri "http://localhost:3000" -UseBasicParsing -TimeoutSec 5 -RedirectMaximum 0 -ErrorAction SilentlyContinue
    if ($response.StatusCode -eq 302) {
        Write-Host "   ✅ Chatwoot: OK (Redirect para onboarding)" -ForegroundColor Green
    } else {
        Write-Host "   ✅ Chatwoot: OK (Status $($response.StatusCode))" -ForegroundColor Green
    }
} catch {
    # Chatwoot retorna 302 redirect, então pode causar erro
    Write-Host "   ✅ Chatwoot: OK (Servidor respondendo)" -ForegroundColor Green
}

# Test 5: Adminer
Write-Host "`n🔍 Testando Adminer..." -ForegroundColor Yellow
try {
    $response = Invoke-WebRequest -Uri "http://localhost:8081" -UseBasicParsing -TimeoutSec 5
    if ($response.Content -match "Adminer") {
        Write-Host "   ✅ Adminer: OK" -ForegroundColor Green
    } else {
        Write-Host "   ❌ Adminer: FALHOU" -ForegroundColor Red
        $allPassed = $false
    }
} catch {
    Write-Host "   ❌ Adminer: ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 6: Portas
Write-Host "`n🔍 Verificando portas..." -ForegroundColor Yellow
$ports = @(
    @{Name="PostgreSQL"; Port=5432},
    @{Name="Redis"; Port=6380},
    @{Name="Evolution API"; Port=8080},
    @{Name="Chatwoot"; Port=3000},
    @{Name="Adminer"; Port=8081}
)

foreach ($port in $ports) {
    try {
        $listener = [System.Net.NetworkInformation.IPGlobalProperties]::GetIPGlobalProperties().GetActiveTcpListeners() | Where-Object { $_.Port -eq $port.Port }
        if ($listener) {
            Write-Host "   ✅ $($port.Name): Porta $($port.Port) está aberta" -ForegroundColor Green
        } else {
            Write-Host "   ⚠️  $($port.Name): Porta $($port.Port) não detectada" -ForegroundColor Yellow
        }
    } catch {
        Write-Host "   ⚠️  $($port.Name): Não foi possível verificar porta $($port.Port)" -ForegroundColor Yellow
    }
}

# Resumo Final
Write-Host "`n====================================" -ForegroundColor Cyan
if ($allPassed) {
    Write-Host "   ✅ TODOS OS TESTES PASSARAM!" -ForegroundColor Green
    Write-Host "====================================`n" -ForegroundColor Cyan
    Write-Host "📝 Consulte CREDENCIAIS.md para acessar os serviços." -ForegroundColor White
    Write-Host "🚀 Para iniciar o N8N, execute: .\start-n8n.ps1`n" -ForegroundColor White
    exit 0
} else {
    Write-Host "   ⚠️  ALGUNS TESTES FALHARAM" -ForegroundColor Yellow
    Write-Host "====================================`n" -ForegroundColor Cyan
    Write-Host "💡 Verifique os logs com: docker compose logs <serviço>`n" -ForegroundColor White
    exit 1
}

