    Write-Host "   ❌ PostgreSQL: ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 2: Redis
Write-Host "`n🔍 Testando Redis..." -ForegroundColor Yellow
try {
    $result = docker exec docker-n8n-evo-redis-1 redis-cli -a oPvT2rgzcoVtwqDCAYhMz76I ping 2>&1
    if ($result -match "PONG") {
        Write-Host "   ✅ Redis: OK" -ForegroundColor Green
    } else {
        Write-Host "   ❌ Redis: FALHOU" -ForegroundColor Red
        $allPassed = $false
    }
} catch {
    Write-Host "   ❌ Redis: ERRO - $_" -ForegroundColor Red
    $allPassed = $false
}

# Test 3: Evolution API
