# SERVEO RESTART SCRIPT - Reinicia todos os túneis Serveo
# =============================================================================
# Uso: .\serveo_restart.ps1
# =============================================================================

Write-Host "`n====================================" -ForegroundColor Cyan
Write-Host "   REINICIANDO TÚNEIS SERVEO" -ForegroundColor Cyan
Write-Host "====================================`n" -ForegroundColor Cyan

# Passo 1: Matar todos os processos SSH existentes
