input.content:
# =============================================================================
# SERVEO MULTI-TUNNELS SCRIPT - Version Simplified
# =============================================================================

Write-Host "`n====================================" -ForegroundColor Cyan
Write-Host "   INICIANDO TUNEIS SERVEO" -ForegroundColor Cyan
Write-Host "====================================`n" -ForegroundColor Cyan

# Cleanup inicial
Write-Host "1. Matando processos SSH antigos..." -ForegroundColor Yellow
try {
    $sshProcesses = Get-Process ssh -ErrorAction SilentlyContinue
    if ($sshProcesses) {
        $sshProcesses | Stop-Process -Force
        Write-Host "   Processos finalizados: $($sshProcesses.Count)" -ForegroundColor Green
    } else {
        Write-Host "   Nenhum processo SSH ativo" -ForegroundColor Green
    }
} catch {
    Write-Host "   $($_.Exception.Message)" -ForegroundColor Yellow
}

Start-Sleep -Seconds 3

# Configuracao dos tuneis
Write-Host "`n2. Iniciando tuneis..." -ForegroundColor Yellow

Write-Host "`n   Chatwoot: https://maceio-chat-v1.serveousercontent.com" -ForegroundColor Cyan
Write-Host "   Evolution: https://maceio-evo-v1.serveousercontent.com" -ForegroundColor Cyan
Write-Host "   N8N: https://maceio-n8n-alfa42.serveousercontent.com" -ForegroundColor Cyan

Write-Host "`n3. Aguardando conexao SSH..." -ForegroundColor Yellow

# Iniciar tuneis em processos separados
$chatwootScript = {
    while ($true) {
        Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Chatwoot tunnel starting..." -ForegroundColor Green
        try {
            & ssh -o ServerAliveInterval=60 `
                  -o ServerAliveCountMax=3 `
                  -o ConnectTimeout=15 `
                  -o TCPKeepAlive=yes `
                  -R maceio-chat-v1:80:localhost:3000 serveo.net
        } catch {
            Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Chatwoot tunnel error: $_" -ForegroundColor Red
        }
        Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Chatwoot tunnel reconnecting in 5s..." -ForegroundColor Yellow
        Start-Sleep -Seconds 5
    }
}

$evolutionScript = {
    while ($true) {
        Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Evolution API tunnel starting..." -ForegroundColor Green
        try {
            & ssh -o ServerAliveInterval=60 `
                  -o ServerAliveCountMax=3 `
                  -o ConnectTimeout=15 `
                  -o TCPKeepAlive=yes `
                  -R maceio-evo-v1:80:localhost:8080 serveo.net
        } catch {
            Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Evolution API tunnel error: $_" -ForegroundColor Red
        }
        Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Evolution API tunnel reconnecting in 5s..." -ForegroundColor Yellow
        Start-Sleep -Seconds 5
    }
}

$n8nScript = {
    while ($true) {
        Write-Host "[$(Get-Date -Format 'HH:mm:ss')] N8N tunnel starting..." -ForegroundColor Green
        try {
            & ssh -o ServerAliveInterval=60 `
                  -o ServerAliveCountMax=3 `
                  -o ConnectTimeout=15 `
                  -o TCPKeepAlive=yes `
                  -R maceio-n8n-alfa42:80:localhost:5678 serveo.net
        } catch {
            Write-Host "[$(Get-Date -Format 'HH:mm:ss')] N8N tunnel error: $_" -ForegroundColor Red
        }
        Write-Host "[$(Get-Date -Format 'HH:mm:ss')] N8N tunnel reconnecting in 5s..." -ForegroundColor Yellow
        Start-Sleep -Seconds 5
    }
}

# Iniciar os 3 tuneis em background
Start-Job -ScriptBlock $chatwootScript -Name "chatwoot-tunnel" | Out-Null
Start-Job -ScriptBlock $evolutionScript -Name "evolution-tunnel" | Out-Null
Start-Job -ScriptBlock $n8nScript -Name "n8n-tunnel" | Out-Null

Write-Host "`n====================================" -ForegroundColor Green
Write-Host "   TUNEIS INICIADOS!" -ForegroundColor Green
Write-Host "====================================`n" -ForegroundColor Green

Write-Host "URLs Publicas:" -ForegroundColor Cyan
Write-Host "  Chatwoot:     https://maceio-chat-v1.serveousercontent.com" -ForegroundColor White
Write-Host "  Evolution:    https://maceio-evo-v1.serveousercontent.com" -ForegroundColor White
Write-Host "  N8N:          https://maceio-n8n-alfa42.serveousercontent.com" -ForegroundColor White

Write-Host "`nPara parar: Ctrl+C ou feche este terminal`n" -ForegroundColor Yellow

# Manter o script rodando
try {
    while ($true) {
        Start-Sleep -Seconds 10

        # Verificar se os jobs ainda estao rodando
        $chatwootJob = Get-Job -Name "chatwoot-tunnel" -ErrorAction SilentlyContinue
        $evolutionJob = Get-Job -Name "evolution-tunnel" -ErrorAction SilentlyContinue
        $n8nJob = Get-Job -Name "n8n-tunnel" -ErrorAction SilentlyContinue

        $activeCount = 0
        if ($chatwootJob) { $activeCount++ }
        if ($evolutionJob) { $activeCount++ }
        if ($n8nJob) { $activeCount++ }

        Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Status: $activeCount/3 tuneis ativos" -ForegroundColor Cyan

        # Se algum job parou, reinicia
        if (-not $chatwootJob) {
            Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Reiniciando Chatwoot tunnel..." -ForegroundColor Yellow
            Start-Job -ScriptBlock $chatwootScript -Name "chatwoot-tunnel" | Out-Null
        }
        if (-not $evolutionJob) {
            Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Reiniciando Evolution tunnel..." -ForegroundColor Yellow
            Start-Job -ScriptBlock $evolutionScript -Name "evolution-tunnel" | Out-Null
        }
        if (-not $n8nJob) {
            Write-Host "[$(Get-Date -Format 'HH:mm:ss')] Reiniciando N8N tunnel..." -ForegroundColor Yellow
            Start-Job -ScriptBlock $n8nScript -Name "n8n-tunnel" | Out-Null
        }
    }
} finally {
    # Cleanup ao sair
    Write-Host "`nParando todos os tuneis..." -ForegroundColor Yellow
    Get-Job | Stop-Job
    Get-Job | Remove-Job
    Get-Process ssh -ErrorAction SilentlyContinue | Stop-Process -Force
    Write-Host "Tuneis parados." -ForegroundColor Green
}

